            (error.message === 'Unauthorized' || error.message === 'Forbidden' || error.message.includes('not found'))) {
            return handleAuthError(error)
        }

        // Handle workflow service errors
        console.error('Workflow service error:', error)
        return NextResponse.json(
            {
                error: 'Workflow service error',
                message: error instanceof Error ? error.message : 'Failed to fetch workflow'
            },
