        )
    }
}

export async function POST(req: NextRequest) {
    try {
        const body = await req.json()
        const { action, projectId, labNumber } = body

        if (!projectId) {
            return NextResponse.json({ error: 'projectId required' }, { status: 400 })
        }

        // Verify authentication and project ownership
        const user = await getAuthUser()
        await verifyProjectOwnership(projectId, user.id)

        if (action === 'START') {
            if (!labNumber) {
                return NextResponse.json({ error: 'labNumber required for START action' }, { status: 400 })
            }

            const workflow = await WorkflowService.startWorkflow(projectId, labNumber)

            if (!workflow) {
                console.error('Failed to start workflow for project:', projectId, 'lab:', labNumber)
                return NextResponse.json(
                    { error: 'Failed to start workflow' },
                    { status: 500 }
                )
            }

            return NextResponse.json({ workflow })
        }

        return NextResponse.json({ error: 'Invalid action' }, { status: 400 })
    } catch (error) {
        // Check if it's an auth error first
        if (error instanceof Error &&
            (error.message === 'Unauthorized' || error.message === 'Forbidden' || error.message.includes('not found'))) {
            return handleAuthError(error)
        }

        // Handle workflow service errors
        console.error('Workflow service error:', error)
        return NextResponse.json(
            {
                error: 'Workflow service error',
                message: error instanceof Error ? error.message : 'Failed to process workflow action'
            },
            { status: 500 }
        )
    }
}

